+  readonly channel = 'webhook' as const;
+  private logger = new Logger('WebhookAdapter');
+  private deliveredPayloads: { url: string; body: WebhookRequestBody }[] = [];
+  private inMemoryTransport: WebhookTransport;
+  private transport: WebhookTransport;
+
+  constructor(private config: WebhookAdapterConfig) {
+    this.inMemoryTransport = async (url: string, body: WebhookRequestBody) => {
+      this.deliveredPayloads.push({ url, body });
+      return `whk-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
+    };
+    this.transport = config.transport ?? this.inMemoryTransport;
+  }
+
+  /**
+   * Format a notification payload into the webhook request body.
+   */
+  formatPayload(payload: NotificationPayload): WebhookRequestBody {
+    return {
+      notificationId: payload.id,
+      type: payload.type,
+      recipient: payload.recipient,
+      subject: payload.subject,
+      body: payload.body,
+      priority: payload.priority,
+      metadata: payload.metadata,
+      timestamp: payload.createdAt.toISOString(),
+    };
+  }
+
+  /**
+   * Send a notification via webhook POST.
+   *
+   * Steps: validate URL → format payload → POST via transport.
+   */
+  async send(payload: NotificationPayload): Promise<DeliveryResult> {
+    this.logger.info(`Preparing webhook to ${this.config.url}: "${payload.subject}"`);
+
+    const url = this.config.url.trim();
+    if (!url) {
+      const error = 'Webhook URL is empty';
+      this.logger.error(error);
+      return { success: false, error };
+    }
+
+    if (!isValidUrl(url)) {
+      const error = `Invalid webhook URL: ${url}`;
+      this.logger.error(error);
+      return { success: false, error };
+    }
+
