+      const deliveryId = await this.transport(url, body);
+      this.logger.info(`Webhook delivered: ${deliveryId} to ${url}`);
+
+      return {
+        success: true,
+        providerMetadata: {
+          url,
+          deliveryId,
+        },
+      };
