/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Formats the notification payload as JSON and POSTs it to a configured URL.
 * Implements a pluggable transport layer (defaults to in-memory for testing).
 *
 * The adapter conforms to the NotificationAdapter interface and is registered
 * with NotificationService via registerAdapter().
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to the webhook endpoint.
 */
export interface WebhookRequestBody {
  notificationId: string;
  type: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  metadata: Record<string, string>;
  timestamp: string;
}

/**
 * Transport function signature — abstracts the actual HTTP POST mechanism.
 * Return a delivery ID on success, or throw on failure.
 */
export type WebhookTransport = (url: string, body: WebhookRequestBody) => Promise<string>;

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookAdapterConfig {
  /** The URL to POST notifications to. */
  url: string;
  /** Optional: secret for signing payloads. */
  secret?: string;
  /** Optional: custom transport function. If not provided, uses in-memory transport. */
  transport?: WebhookTransport;
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveredPayloads: { url: string; body: WebhookRequestBody }[] = [];
  private inMemoryTransport: WebhookTransport;
  private transport: WebhookTransport;

  constructor(private config: WebhookAdapterConfig) {
    this.inMemoryTransport = async (url: string, body: WebhookRequestBody) => {
      this.deliveredPayloads.push({ url, body });
      return `whk-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    };
    this.transport = config.transport ?? this.inMemoryTransport;
  }

  /**
   * Format a notification payload into the webhook request body.
   */
  formatPayload(payload: NotificationPayload): WebhookRequestBody {
    return {
      notificationId: payload.id,
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      metadata: payload.metadata,
      timestamp: payload.createdAt.toISOString(),
    };
  }

  /**
   * Send a notification via webhook POST.
   *
   * Steps: validate URL → format payload → POST via transport.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    this.logger.info(`Preparing webhook to ${this.config.url}: "${payload.subject}"`);

    const url = this.config.url.trim();
    if (!url) {
      const error = 'Webhook URL is empty';
      this.logger.error(error);
      return { success: false, error };
    }

    if (!isValidUrl(url)) {
      const error = `Invalid webhook URL: ${url}`;
      this.logger.error(error);
      return { success: false, error };
    }

    const body = this.formatPayload(payload);

    try {
      const deliveryId = await this.transport(url, body);
      this.logger.info(`Webhook delivered: ${deliveryId} to ${url}`);

      return {
        success: true,
        providerMetadata: {
          url,
          deliveryId,
        },
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Transport error';
      this.logger.error(`Webhook delivery failed: ${errorMessage}`);
      return { success: false, error: errorMessage };
    }
  }

  /**
   * Get all payloads delivered through this adapter (for testing).
   */
  getDeliveredPayloads(): { url: string; body: WebhookRequestBody }[] {
    return [...this.deliveredPayloads];
  }

  /**
   * Clear delivered payload records (for testing).
   */
  clearDeliveredPayloads(): void {
    this.deliveredPayloads = [];
  }
}

/**
 * Basic URL validation — checks for http:// or https:// prefix.
 */
function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

