import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { WebhookTransport, WebhookRequestBody } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'webhook',
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
  });

  describe('send', () => {
    it('should successfully send a webhook notification', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerMetadata?.url).toBe('https://hooks.example.com/notify');
      expect(result.providerMetadata?.deliveryId).toBeDefined();
    });

    it('should record delivered payloads in-memory', async () => {
      await adapter.send(makePayload());

      const delivered = adapter.getDeliveredPayloads();
      expect(delivered).toHaveLength(1);
      expect(delivered[0]?.url).toBe('https://hooks.example.com/notify');
      expect(delivered[0]?.body.notificationId).toBe('notif-0001');
      expect(delivered[0]?.body.subject).toBe('Order Confirmation: order-1');
    });

    it('should fail for empty URL', async () => {
      const emptyAdapter = new WebhookAdapter({ url: '' });
      const result = await emptyAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
    });

    it('should fail for invalid URL', async () => {
      const badAdapter = new WebhookAdapter({ url: 'not-a-url' });
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should fail for non-HTTP URL', async () => {
      const ftpAdapter = new WebhookAdapter({ url: 'ftp://files.example.com/hook' });
      const result = await ftpAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: WebhookTransport = async () => {
        throw new Error('Connection refused');
      };
      const failAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com/notify',
        transport: failingTransport,
      });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });

    it('should use custom transport when provided', async () => {
      const deliveries: { url: string; body: WebhookRequestBody }[] = [];
      const customTransport: WebhookTransport = async (url, body) => {
        deliveries.push({ url, body });
        return 'custom-delivery-id';
      };
      const customAdapter = new WebhookAdapter({
        url: 'https://custom.example.com/hook',
        transport: customTransport,
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerMetadata?.deliveryId).toBe('custom-delivery-id');
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://custom.example.com/hook');
    });

    it('should accept HTTP URLs', async () => {
      const httpAdapter = new WebhookAdapter({ url: 'http://internal.example.com/hook' });
      const result = await httpAdapter.send(makePayload());

      expect(result.success).toBe(true);
    });
  });

  describe('formatPayload', () => {
    it('should format notification payload as webhook request body', () => {
      const payload = makePayload();
      const body = adapter.formatPayload(payload);

      expect(body.notificationId).toBe('notif-0001');
      expect(body.type).toBe('order_confirmation');
      expect(body.recipient).toBe('https://hooks.example.com/notify');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toBe('Your order has been placed. Items: Widget x2. Total: $20.00');
      expect(body.priority).toBe('normal');
      expect(body.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
      expect(body.timestamp).toBe('2026-01-15T10:00:00.000Z');
    });

    it('should include all metadata fields', () => {
      const body = adapter.formatPayload(
        makePayload({
          metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
        }),
      );

      expect(body.metadata).toEqual({
        orderId: 'order-1',
        previousStatus: 'pending',
        newStatus: 'confirmed',
      });
    });

    it('should handle empty metadata', () => {
      const body = adapter.formatPayload(makePayload({ metadata: {} }));
      expect(body.metadata).toEqual({});
    });
  });

  describe('clearDeliveredPayloads', () => {
    it('should clear all recorded deliveries', async () => {
      await adapter.send(makePayload());
      expect(adapter.getDeliveredPayloads()).toHaveLength(1);

      adapter.clearDeliveredPayloads();
      expect(adapter.getDeliveredPayloads()).toHaveLength(0);
    });
  });

  describe('channel property', () => {
    it('should report webhook as its channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });
});

